+                    \\                /* Recursive call {d} - push frame */
+                    \\                {{
+                    \\                    JSValue arg = POP();
+                    \\                    frame->sp = sp;
+                    \\                    frame->instr_offset = {d};  /* Resume at next phase */
+                    \\                    frame->waiting_for_call = 1;
